var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":" 따끈따끈한 소식이야, 블랙 네트워크 친구들.","JPN":" アツアツのニュースだよ、ブラックネットワークのみんな。","ENG":"I have some juicy news, my fellow Dark Network members.","TWN":"各位黑色網路的網友們，告訴大家一個最新消息！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":" 내 친구가 관리국에서 일하는데, 고심도 좌표에서 어떤 미친놈들이 다른 태스크포스들을 습격하는 것 같아.","JPN":" 私の友達が管理局で働いてるんだけど、高深度の座標でイカれた奴らが他のタスクフォースを襲撃してるみたい。","ENG":"I have a friend that works at the Administration, and it seems that some crazy goons are attacking another TASKFORCE at some hyperdepth coordinates.","TWN":"我朋友在管理局做事，據說在高深度座標有群瘋子突襲其他特遣勢力欸！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 스캐빈저다. 그놈들 결국 저질렀군.","JPN":" ┕ スカベンジャーだ。あいつら結局やらかしたな。","ENG":"┕ It’s the Scavengers. So, they’ve thrown the dice.","TWN":" ┕ 是清道夫幹的，他們終究還是幹下這種壞事。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 저질렀군이랜다ㅋㅋㅋ 너 때문에 웃으면서 출근함.","JPN":" ┕ やらかしたな、だってｗｗｗ　お前のおかげで出勤中笑ったよ。","ENG":"┕ \\"Thrown the dice\\" LOL. I’m starting my day with a good laugh thanks to you. Haha!","TWN":" ┕ 壞人不幹壞事幹什麼，ㄎㄎㄎ 被你笑死。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 세상의 멸망이 다가왔습니다! 회개하십시오!","JPN":" ┕ 世界の滅亡が近づいてきました！　悔い改めなさい！","ENG":"┕ The end of the world has come! Repent!","TWN":" ┕ 世界末日即將到來，趕快悔改！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 아니 근데 진짜면 좀 심각한 거 아님? 왜 공문 하나 안 오냐?","JPN":" ┕ いや、でも本当ならマジやばくね？　なんで公文書とか送られてこないの？","ENG":"┕ No, but on a serious note, isn’t this a big deal? Why aren’t there any announcements?","TWN":" ┕ 如果是真的，那事情這麼大條怎麼都沒收到公文？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 멸망이고 나발이고 난 오늘 휴가 짤려서 채굴 나감. 수구.","JPN":" ┕ 滅亡も何も、俺は今日有給拒否されて採掘に行くよ。乙。","ENG":"┕ Who cares about the end of the world? My leave request got denied, so I’m off to the mines. Smell ya later","TWN":" ┕ 管他是末日還是胡說八道，我只知道我今天休假被取消要去開採，哭哭。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":" 반복한다! 이 구조 요청은 관리국이 지정한 단파 회선을 통해 송신 중이다!","JPN":" 繰り返す！　この救助要請は管理局が指定した短波回線から送信している！","ENG":"I repeat! This is a mayday broadcast on the Administration-designated shortwave line!","TWN":"再重複一次！這個求救訊號是透過管理局指定的短波天線傳送的！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":" 현재 우리는 심도 4에서 채굴 중에 철갑옷을 입은 기사들에게 공격 받고 있다!","JPN":" 現在我々は深度4での採掘作業中、鉄の鎧を着た騎士たちに攻撃されている！","ENG":"We were attacked by armored knights while mining in Depth 4 and are pinned down!","TWN":"我們在深度4開採途中受到身穿鎧甲的騎士攻擊！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":" 스캐빈저든 누구든 좋아! 이 무전을 듣는다면 도움을──","JPN":" スカベンジャーでも誰でもいい！　この通信を聞いたら助けを――","ENG":"Whether it be Scavengers or whoever, if you can hear this broadcast, please help─","TWN":"清道夫也好，誰都好！聽到這個無線電請來支──"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……클리포트 게임?","JPN":"……クリフォトゲーム？","ENG":"...Qliphoth Game?","TWN":"……逆卡巴拉遊戲？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다. 구 관리국은 본래 클리포트 게임을 저지하기 위해 결성된 조직이니까요.","JPN":"そうです。旧管理局は本来、クリフォトゲームを阻止するために結成された組織ですから。","ENG":"That’s correct. The Old Administration was originally established to prevent the Qliphoth Game.","TWN":"沒錯，舊管理局原本就是為阻止逆卡巴拉遊戲而成立的組織。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당신이 구 관리국의 올드 카운터 출신이라는 것도 그렇고……","JPN":"君が旧管理局のオールドカウンター出身だというのもそうだが……","ENG":"Including the fact that you were an Old Counter from the Old Administration...","TWN":"你是從舊管理局時期就存在的制裁者嗎……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"오늘은 하나같이 놀랄 만한 일들뿐이군.","JPN":"今日はすべて驚かされることばかりだな。","ENG":"Today is simply full of surprises.","TWN":"包括這件事在內，今天淨是些令人驚訝的事呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당신 말대로라면 그 허신이라는 괴물도 클리포트 게임의 전조에 불과하다는 건가?","JPN":"君のいうとおりなら、あの虚神という化け物もクリフォトゲームの前兆に過ぎないということか？","ENG":"So, if we assume that what you’re saying is correct, the monster called \\"Hollow God\\" is merely harbingers of the Qliphoth Game?","TWN":"若照你所說，那個叫作幻神的怪物，不過就是逆卡巴拉遊戲的序幕而已嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정확한 표현은 아닙니다만…… 비슷합니다.","JPN":"正しい表現ではありませんが……似たようなものです。","ENG":"Although not a completely accurate description, it’s close enough.","TWN":"這個說法不太準確……但類似這樣沒錯。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"허신은 분명 강력한 존재입니다.","JPN":"虚神は確かに強力な存在です。","ENG":"The Hollow Gods are powerful beings, no doubt about that.","TWN":"幻神的威力不容小覷。"},"stage":{"bg":"MAINSTREAM_808","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};